  ('real-estate-moex-00165', 'real-estate', 'real-estate-moex-113-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依平均地權條例規定，預售屋或新建成屋買賣契約之買受人，於簽訂買賣契約後，不得讓與或轉 售買賣契約與第三人，但經其他中央主管機關公告得讓與或轉售之情形並經直轄市、縣（市）主 管機關核准者，不在此限。買受人據此得讓與或轉售之戶（棟）數為何？', '["全國每一年以一戶（棟）為限", "全國每一年以二戶（棟）為限", "全國每二年以一戶（棟）為限", "全國每二年以三戶（棟）為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "64710a5e50e5", "answer_pdf_sha1": "26b2395307c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00166', 'real-estate', 'real-estate-moex-113-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依平均地權條例規定，權利人及義務人應於買賣案件申請所有權移轉登記時，申報登錄資訊，未 共同申報登錄資訊者，直轄市、縣（市）主管機關應令其限期申報登錄資訊；屆期未申報登錄資 訊，買賣案件已辦竣所有權移轉登記者，處多少罰鍰，並令其限期改正？', '["新臺幣三萬元以上十五萬元以下罰鍰", "新臺幣六萬元以上三十萬元以下罰鍰", "新臺幣十五萬元以上五十萬元以下罰鍰", "新臺幣三十萬元以上一百萬元以下罰鍰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "64710a5e50e5", "answer_pdf_sha1": "26b2395307c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00167', 'real-estate', 'real-estate-moex-113-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依平均地權條例規定，有關私法人買受供住宅使用之房屋，下列何者正確？', '["應檢具切結書，經中央主管機關許可", "中央主管機關審核其使用計畫，以合議制方式辦理", "私法人取得之房屋，於登記完畢後十年內不得辦理預告登記", "許可之文件有效期限為二年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "64710a5e50e5", "answer_pdf_sha1": "26b2395307c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
